/* ================================================
   GENERACIÓN DE PDF (MÁRGENES ESTRECHAS + CAJA DE FECHA AJUSTADA)
   ================================================ */
function generatePDF(action = 'download') {
  const r = DB.getRemision(currentViewId);
  const c = DB.getCliente(r.clienteId);
  const { jsPDF } = window.jspdf;

  const doc = new jsPDF({
    orientation: 'p',
    unit: 'mm',
    format: 'a4'
  });

  const pageW = 210;
  const pageH = 297;
  const margin = 10; // Margen estrecha (1 cm)
  const contentW = pageW - margin * 2; // 190mm
  let y = margin + 5; 

  const greenColor = [50, 168, 23]; // Tu verde #32A817

  // --- LOGO ---
  doc.addImage(logoEmpresa, 'PNG', margin, y, 46, 20);

  // --- CONSECUTIVO ---
  doc.setTextColor(...greenColor);
  doc.setFontSize(22);
  doc.setFont('Helvetica', 'bold');
  doc.text(r.consecutivo, pageW - margin, y + 10, { align: 'right' });

  // --- FECHA ---
  doc.setTextColor(0, 0, 0);
  doc.setFontSize(11);
  doc.setFont('Helvetica', 'bold');
  // Movemos la etiqueta "Fecha:" un poco más a la izquierda (ahora a 48mm del borde) para dar espacio a la nueva caja
  doc.text('Fecha:', pageW - margin - 48, y + 22);
  
  // AJUSTE: Ampliamos la cajita de la fecha a 34mm de ancho (antes era de 26mm)
  doc.setDrawColor(...greenColor);
  doc.setLineWidth(0.3);
  doc.roundedRect(pageW - margin - 34, y + 17, 34, 7, 2, 2, 'S');

  const fechaObj = new Date(r.fecha + 'T00:00:00');
  const d = String(fechaObj.getDate()).padStart(2, '0');
  const m = String(fechaObj.getMonth() + 1).padStart(2, '0');
  const yyyy = fechaObj.getFullYear();
  
  doc.setFont('Helvetica', 'normal');
  doc.setFontSize(10); // Lo subimos a tamaño 10 para aprovechar mejor el nuevo espacio
  doc.setTextColor(0, 0, 0);
  // AJUSTE: Centramos el texto exactamente en la mitad de la nueva caja (a 17mm del borde derecho)
  doc.text(`${d}   /   ${m}   /   ${yyyy}`, pageW - margin - 17, y + 21.5, { align: 'center' });

  y += 35;

  // --- INFORMACIÓN DEL CLIENTE (GRILLA) ---
  const rowH = 8;
  const col1W = 28;
  const col2Start = margin + contentW / 2;
  const col2LabelW = 24;

  doc.setDrawColor(...greenColor);
  doc.setLineWidth(0.3);
  
  // Borde exterior
  doc.rect(margin, y, contentW, rowH * 3, 'S');
  
  // Líneas Horizontales de la grilla
  doc.line(margin, y + rowH, pageW - margin, y + rowH);
  doc.line(margin, y + rowH * 2, pageW - margin, y + rowH * 2);

  // Líneas Verticales
  doc.line(col2Start, y, col2Start, y + rowH * 2); 
  doc.line(margin + col1W, y, margin + col1W, y + rowH * 2); 
  doc.line(col2Start + col2LabelW, y, col2Start + col2LabelW, y + rowH * 2); 

  // Textos del Cliente
  doc.setTextColor(0, 0, 0);
  doc.setFontSize(10);
  
  // Fila 1
  doc.setFont('Helvetica', 'bold'); // Título en Negrita
  doc.text('NOMBRE:', margin + 2, y + 5.5);
  doc.setFont('Helvetica', 'normal'); // Dato Normal
  doc.text((c?.nombre || '').substring(0,40), margin + col1W + 2, y + 5.5);
  
  doc.setFont('Helvetica', 'bold'); // Título en Negrita
  doc.text('TELEFONO:', col2Start + 2, y + 5.5);
  doc.setFont('Helvetica', 'normal'); // Dato Normal
  doc.text((c?.telefono || '').substring(0,40), col2Start + col2LabelW + 2, y + 5.5);
  
  // Fila 2
  doc.setFont('Helvetica', 'bold'); // Título en Negrita
  doc.text('DIRECCION:', margin + 2, y + rowH + 5.5);
  doc.setFont('Helvetica', 'normal'); // Dato Normal
  doc.text((c?.direccion || '').substring(0,40), margin + col1W + 2, y + rowH + 5.5);
  
  doc.setFont('Helvetica', 'bold'); // Título en Negrita
  doc.text('CIUDAD:', col2Start + 2, y + rowH + 5.5);
  doc.setFont('Helvetica', 'normal'); // Dato Normal
  doc.text((c?.ciudad || '').substring(0,40), col2Start + col2LabelW + 2, y + rowH + 5.5);

  // Fila 3
  doc.setFont('Helvetica', 'bold'); // Título en Negrita
  doc.text('OBSERVACIONES:', margin + 2, y + rowH * 2 + 5.5);
  doc.setFont('Helvetica', 'normal'); // Dato Normal
  doc.text((r.observaciones || '').substring(0, 115), margin + 36, y + rowH * 2 + 5.5);

  y += (rowH * 3) + 15;

  // --- TABLA DE ÍTEMS ---
  const headerH = 8;
  const itemH = 7;
  
  const cW = [10, 62, 20, 42, 56]; 
  const cX = [margin, margin + cW[0], margin + cW[0] + cW[1], margin + cW[0] + cW[1] + cW[2], margin + cW[0] + cW[1] + cW[2] + cW[3]];

  // Fondo del Encabezado
  doc.setFillColor(...greenColor);
  doc.roundedRect(margin, y, contentW, headerH, 2, 2, 'F');
  doc.rect(margin, y + headerH/2, contentW, headerH/2, 'F'); 

  // Textos del Encabezado
  doc.setTextColor(255, 255, 255);
  doc.setFontSize(9);
  doc.setFont('Helvetica', 'bold');
  
  doc.text('#', cX[0] + cW[0]/2, y + 5.5, { align: 'center' });
  doc.text('Descripción', cX[1] + cW[1]/2, y + 5.5, { align: 'center' });
  doc.text('Cantidad', cX[2] + cW[2]/2, y + 5.5, { align: 'center' });
  doc.text('Serial/Referencia', cX[3] + cW[3]/2, y + 5.5, { align: 'center' });
  doc.text('Observaciones', cX[4] + cW[4]/2, y + 5.5, { align: 'center' });

  // Líneas separadoras blancas
  doc.setDrawColor(255, 255, 255);
  doc.setLineWidth(0.2);
  for(let i=1; i<cX.length; i++) doc.line(cX[i], y, cX[i], y + headerH);

  y += headerH;

  // Filas de datos (Dinámicas)
  doc.setTextColor(0, 0, 0);
  doc.setFontSize(9);
  doc.setFont('Helvetica', 'normal');
  doc.setDrawColor(...greenColor);
  doc.setLineWidth(0.3);

  const numRows = Math.max(1, r.items ? r.items.length : 0);

  for (let i = 0; i < numRows; i++) {
    const item = r.items && r.items[i] ? r.items[i] : null;
    
    doc.text(String(i + 1), cX[0] + cW[0]/2, y + 5, { align: 'center' });
    if (item) {
      doc.text((item.descripcion || '').substring(0,40), cX[1] + 2, y + 5);
      doc.text(String(item.cantidad || ''), cX[2] + cW[2]/2, y + 5, { align: 'center' });
      doc.text((item.serial || '').substring(0,25), cX[3] + 2, y + 5);
      doc.text((item.observaciones || '').substring(0,35), cX[4] + 2, y + 5);
    }
    
    if (i === numRows - 1) { 
       doc.roundedRect(margin, y, contentW, itemH, 2, 2, 'S');
       doc.line(margin, y, pageW - margin, y); 
    } else {
       doc.rect(margin, y, contentW, itemH, 'S');
    }
    
    for(let j=1; j<cX.length; j++) doc.line(cX[j], y, cX[j], y + itemH);
    
    y += itemH;
  }

  // --- FIRMAS ---
  y += 30; 
  
  const sigW = 60; 
  
  doc.setDrawColor(...greenColor);
  doc.setLineWidth(0.25);
  doc.line(margin + 10, y, margin + 10 + sigW, y);
  doc.line(pageW - margin - 10 - sigW, y, pageW - margin - 10, y);

  doc.setTextColor(0, 0, 0);
  doc.setFontSize(11);
  doc.setFont('Helvetica', 'bold');
  doc.text('ENTREGA', margin + 10 + sigW/2, y + 7, { align: 'center' });
  doc.text('RECIBE', pageW - margin - 10 - sigW/2, y + 7, { align: 'center' });

  // Lógica de descarga o vista previa
  if (action === 'print') {
    const blob = doc.output('blob');
    const blobUrl = URL.createObjectURL(blob);
    window.open(blobUrl, '_blank');
  } else {
    doc.save(`${r.consecutivo}.pdf`);
    toast(`PDF generado: ${r.consecutivo}.pdf`);
  }
}

// Nombramos la función que tu botón HTML está buscando
function printCurrentRemision() {
  generatePDF('print');
}

/* ================================================
   DASHBOARD
   ================================================ */
function renderDashboard() {
  const total = DB.remisiones.length;
  const totalCli = DB.clientes.length;
  const totalItems = DB.remisiones.reduce((a,r)=>a+(r.items?.length||0),0);
  const today = todayISO();
  const hoy = DB.remisiones.filter(r=>r.fecha===today).length;

  document.getElementById('stat-total-rem').textContent = total;
  document.getElementById('stat-total-cli').textContent = totalCli;
  document.getElementById('stat-total-items').textContent = totalItems;
  document.getElementById('stat-hoy').textContent = hoy;
  document.getElementById('badge-remisiones').textContent = total;
  document.getElementById('badge-clientes').textContent = totalCli;

  const tbody = document.getElementById('recent-tbody');
  const recent = DB.remisiones.slice(0, 5);
  if (!recent.length) {
    tbody.innerHTML = `<tr><td colspan="5"><div class="empty-state" style="padding:32px">
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8z"/><polyline points="14 2 14 8 20 8"/></svg>
      <p>No hay remisiones creadas aún</p>
    </div></td></tr>`;
    return;
  }
  tbody.innerHTML = recent.map(r => {
    const c = DB.getCliente(r.clienteId);
    return `<tr>
      <td><span class="cons-code">${esc(r.consecutivo)}</span></td>
      <td class="fw-600">${esc(c?.nombre||'—')}</td>
      <td>${fmtDate(r.fecha)}</td>
      <td><span class="badge badge-blue">${r.items?.length||0}</span></td>
      <td>
        <div class="flex gap-8">
          <button class="btn btn-outline btn-sm" onclick="viewRemision('${r.id}')">Ver PDF</button>
        </div>
      </td>
    </tr>`;
  }).join('');
}

/* ================================================
   QUICK CLIENT (inline inside remision modal)
   ================================================ */
function toggleQuickCliente() {
  const form = document.getElementById('quick-cliente-form');
  const isHidden = form.style.display === 'none';
  form.style.display = isHidden ? 'block' : 'none';
  if (isHidden) {
    ['qcli-nombre','qcli-telefono','qcli-ciudad','qcli-conductor','qcli-direccion','qcli-correo']
      .forEach(id => { const el = document.getElementById(id); if(el) el.value = ''; });
    setTimeout(() => document.getElementById('qcli-nombre')?.focus(), 60);
  }
}

function saveQuickCliente() {
  const nombre = document.getElementById('qcli-nombre').value.trim();
  const ciudad = document.getElementById('qcli-ciudad').value.trim();
  const correo = document.getElementById('qcli-correo').value.trim();
  const telefono = document.getElementById('qcli-telefono').value.trim();

  if (!nombre) { toast('El nombre del cliente es requerido', 'error'); return; }
  if (!ciudad) { toast('La ciudad es requerida', 'error'); return; }
  if (!validarCorreo(correo)) { toast('El formato del correo es inválido', 'error'); return; }
  if (!validarTelefono(telefono)) { toast('El teléfono contiene caracteres inválidos', 'error'); return; }

  const obj = {
    id: uid(),
    nombre,
    telefono,
    direccion: document.getElementById('qcli-direccion').value.trim(),
    ciudad,
    correo,
    conductor: document.getElementById('qcli-conductor').value.trim(),
    creadoEn: todayISO()
  };

  DB.clientes.unshift(obj);
  DB.saveClienteToCloud(obj);
  updateSelects();
  document.getElementById('rem-cliente-id').value = obj.id;
  document.getElementById('quick-cliente-form').style.display = 'none';
  document.getElementById('badge-clientes').textContent = DB.clientes.length;
  document.getElementById('stat-total-cli').textContent = DB.clientes.length;

  toast(`✓ Cliente "${obj.nombre}" creado y seleccionado`);
}

/* ================================================
   UPDATE SELECTS
   ================================================ */
function updateSelects() {
  const sel = document.getElementById('rem-cliente-id');
  if (!sel) return;
  const cur = sel.value;
  sel.innerHTML = '<option value="">— Seleccionar cliente —</option>' +
    DB.clientes.map(c => `<option value="${c.id}" ${c.id===cur?'selected':''}>${esc(c.nombre)} — ${esc(c.ciudad)}</option>`).join('');
}

/* ================================================
   INIT - LISTENERS
   ================================================ */
// 1. Keyboard ESC closes modals
document.addEventListener('keydown', e => {
  if (e.key === 'Escape') {
    document.querySelectorAll('.modal-overlay.open').forEach(m => {
      // Ignorar si es el modal de confirmación
      if (m.id === 'modal-confirm') {
        m.classList.remove('open');
        return;
      }
      
      // Chequeo especial para el modal de remisión
      if (m.id === 'modal-remision') {
        const items = document.querySelectorAll('#items-container .item-row').length;
        if (items > 0) {
          const confirmar = window.confirm("¿Seguro que deseas salir? Perderás los datos no guardados.");
          if (!confirmar) return; 
        }
      }
      
      m.classList.remove('open');
    });
  }
}); // <--- ESTA LLAVE FALTABA AQUÍ PARA CERRAR EL ESCAPE

// 2. Escuchar "Enter" en el login (Fuera del evento anterior)
const inputPassword = document.getElementById('login-password');
if (inputPassword) {
  inputPassword.addEventListener('keypress', function (e) {
    if (e.key === 'Enter') {
      iniciarSesion(); 
    }
  });
}

const inputEmail = document.getElementById('login-email');
if (inputEmail) {
  inputEmail.addEventListener('keypress', function (e) {
    if (e.key === 'Enter') {
      inputPassword.focus(); 
    }
  });
}
